def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the most repetition and containing the corresponding count.
    If several letters have the same occurrence, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    if not test:
        return {}

    # Split the input string into a list of words (letters)
    words = test.split()

    # Create a dictionary to store the frequency of each letter
    freq_dict = {}
    for word in words:
        if word in freq_dict:
            freq_dict[word] += 1
        else:
            freq_dict[word] = 1

    # Find the maximum frequency
    max_freq = max(freq_dict.values(), default=0)

    # Filter the dictionary to only include letters with the maximum frequency
    result = {letter: count for letter, count in freq_dict.items() if count == max_freq}

    return result

