def intersection(interval1, interval2):
    start_max = max(interval1[0], interval2[0])
    end_min = min(interval1[1], interval2[1])

    # Check for non-overlapping or zero-length intervals
    if start_max >= end_min:
        return "NO"

    # Explicitly handle the case where intervals are exactly the same
    if interval1 == interval2:
        return "NO"

    length_of_intersection = end_min - start_max

    if is_prime(length_of_intersection):
        return "YES"
    else:
        return "NO"

def tri(n):
    """Function to generate the first n+1 numbers of the Tribonacci sequence."""
    if n == 0:
        return [1]
    elif n == 1:
        return [1, 3]

    # Initialize the sequence with base cases
    tribonacci = [1, 3]

    for i in range(2, n + 1):
        if i % 2 == 0:
            tribonacci.append(1 + i // 2)
        else:
            # Calculate the next value for odd indices
            next_value = tribonacci[-1] + tribonacci[-2] + (1 + (i + 1) // 2)
            tribonacci.append(next_value)

    return tribonacci

