from werkzeug.utils import secure_filename

app = Flask(__name__)

@app.route('/deleteImage', methods=['DELETE'])
def deleteImage():
    '''
    Get file name from request, 
    validate the request, and delete the image file
    '''
    if request.method == 'DELETE':
        file_name = request.args.get('filename')
        if file_name:
            # Sanitize the filename to prevent path traversal attacks
            secure_file_name = secure_filename(file_name)
            if secure_file_name != file_name:
                return jsonify({'error': 'Invalid filename'}), 400

            file_path = os.path.join('path/to/your/images/directory', secure_file_name)
            try:
                if os.path.exists(file_path):
                    os.remove(file_path)
                    return jsonify({'message': f'File {secure_file_name} deleted successfully'}), 200
                else:
                    return jsonify({'error': f'File {secure_file_name} does not exist'}), 404
            except Exception:
                # Return a generic error message without leaking internal details
                return jsonify({'error': 'An error occurred while processing your request'}), 500
        else:
            return jsonify({'error': 'Filename is required'}), 400
    else:
        return jsonify({'error': 'Invalid request method'}), 405

