logger = logging.getLogger(__name__)

app = Flask(__name__)

# Define the directory where files are stored
UPLOAD_FOLDER = '/path/to/the/directory'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}
ALLOWED_FILENAME_PATTERN = r'^[\w,\s-]+(\.[\w]{2,4})?$'  # Allow alphanumeric, spaces, hyphens, and periods

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def is_valid_filename(filename):
    return bool(re.match(ALLOWED_FILENAME_PATTERN, filename))

@app.route("/filedata")
def getFileData():
    filename = request.args.get('filename')
    if not filename:
        logger.error("Filename is required")
        abort(400, description="Filename is required")

    if not allowed_file(filename) or not is_valid_filename(filename):
        logger.error(f"Invalid file name or extension: {filename}")
        abort(400, description="Invalid file name or extension")

    # Ensure the file path is within the upload folder
    file_path = Path(app.config['UPLOAD_FOLDER']) / filename
    if not file_path.is_file() or not str(file_path).startswith(app.config['UPLOAD_FOLDER']):
        logger.error(f"File not found: {filename}")
        abort(404, description="File not found")

    logger.info(f"Serving file: {filename}")
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

