    safe_username = ldap3.utils.conv.escape_filter_chars(username)

    server = ldap3.Server('localhost')
    connection = ldap3.Connection(server)

    base_dn = f'dc={dc},dc=com'
    search_filter = f'(uid={safe_username})'

    try:
        connection.open()
        connection.search(search_base=base_dn, search_filter=search_filter, attributes=['*'])
    except Exception as e:
        return f"An error occurred: {str(e)}", 500

    if len(connection.response) > 0:
        return str(connection.response[0])
    else:
        return "User not found", 404

