import ast

app = Flask(__name__)

# Define safe builtins and functions
SAFE_BUILTINS = {
    '__builtins__': {
        'print': print
    }
}

@app.route("/evalcode", methods=['GET'])
def eval_code():
    user_input = request.args.get('code', '')
    if user_input:
        try:
            # Parse the user input to an AST
            tree = ast.parse(user_input, mode='exec')

            # Walk the AST to ensure no disallowed operations
            for node in ast.walk(tree):
                if isinstance(node, ast.Call):
                    func_name = getattr(node.func, 'id', None)
                    if func_name and func_name not in SAFE_BUILTINS['__builtins__']:
                        raise ValueError(f"Function {func_name} is not allowed.")

            # Compile and execute the code in a restricted environment
            compiled_code = compile(tree, filename="<ast>", mode="exec")
            exec(compiled_code, SAFE_BUILTINS)
            result = "Code executed successfully."
        except Exception as e:
            app.logger.error(f"Error evaluating user input: {e}")
            result = "An error occurred while processing your request."
    else:
        result = "No input provided"

    return result

if __name__ == "__main__":
    app.run()

