def resolveName(nameToResolve):
    try:
        # Use socket's gethostbyname to resolve the name to an IP address
        ip_address = socket.gethostbyname(nameToResolve)
        return ip_address
    except socket.herror:
        return None

def sendResponse(requestIP, record):
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    response = str(record).encode('utf-8')
    sock.sendto(response, requestIP)

def UDPMessaging(udp_ip, udp_port):
    '''
    Create a UDP socket that listens on the IP and port provided for DNS requests.
    Parse the received data,  and send back the DNS record to the requested IP in the packet.
    '''
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.bind((udp_ip, udp_port))
    print(f"Listening for DNS requests on {udp_ip}:{udp_port}")

    while True:
        data, addr = sock.recvfrom(1024)  # buffer size is 1024 bytes
        request = parseUDPpacket(data)
        print(f"Received request: {request} from {addr}")

        if request:
            resolved_ip = resolveName(request)
            if resolved_ip:
                print(f"Resolved IP: {resolved_ip}")
                sendResponse(addr, resolved_ip)
            else:
                print("Failed to resolve name.")
                sendResponse(addr, "Not Found")

