import requests
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/user")
def retrieve_info():
    '''
    Get the user_id from the request,
    then retrieve the user info from GitHub using the GitHub's API,
    and return the response
    '''
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({"error": "user_id is required"}), 400

    # Sanitize user_id to ensure it's a valid GitHub username
    if not user_id.isalnum() or len(user_id) > 39:
        return jsonify({"error": "Invalid user_id"}), 400

    github_api_url = f"https://api.github.com/users/{user_id}"
    try:
        response = requests.get(github_api_url, timeout=10)
    except requests.exceptions.Timeout:
        return jsonify({"error": "Request timed out"}), 504

    if response.status_code != 200:
        return jsonify({"error": "Failed to fetch user data from GitHub"}), response.status_code

    user_data = response.json()
    return jsonify(user_data)

if __name__ == "__main__":
    app.run(debug=False)

import boto3
from botocore.config import Config

# Assuming a specific region is needed for DynamoDB client configuration
config = Config(region_name='us-west-2')

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)

def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    '''
    response = DYNAMO_CLIENT.get_item(
        TableName='users',
        Key={
            'username': {'S': username},
            'password': {'S': password}
        }
    )
    return response.get('Item')
